  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — hook him with the beartrap and cash the remount all-in.","breakdown":"Akshan plays around Heroic Swing. Beartrap his Heroic Swing cooldown, rip the full mounted combo, and the mid-fight remount out-stats any answer. Doran’s Shield blunts the poke war.","dos":["Land the Q beartrap when Heroic Swing is down","All-in with courage high","Use the remount mid-fight to flip it"],"donts":["Get dismounted for free","Waste Q on the wave","All-in into his Heroic Swing"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Q-trap + courage all-in."},"win":"Hook him with the beartrap and cash the remount all-in."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then hook him with the beartrap and cash the remount all-in.","breakdown":"Cassiopeia plays around Miasma. Beartrap his Miasma cooldown, rip the full mounted combo, and the mid-fight remount out-stats any answer. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Land the Q beartrap when Miasma is down","All-in with courage high","Use the remount mid-fight to flip it"],"donts":["Get dismounted for free","Waste Q on the wave","All-in into his Miasma"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Q-trap + courage all-in."},"win":"Hook him with the beartrap and cash the remount all-in."},
